sql_answer:
SELECT name
FROM bridge
WHERE length_meters > (
    SELECT avg(length_meters)
    FROM bridge
);

SELECT name
FROM mill
WHERE built_year BETWEEN 1820 AND 1860;

SELECT architect_id FROM bridge
EXCEPT
SELECT architect_id FROM mill;

SELECT name 
FROM architect 
WHERE nationality LIKE '%,%';

SELECT id FROM bridge
INTERSECT
SELECT built_year FROM mill;

SELECT Airport_Name 
FROM airport 
WHERE Total_Passengers > 20000000;

SELECT Name
FROM pilot
WHERE Age BETWEEN 25 AND 30;

SELECT Airport_Name
FROM airport
WHERE International_Passengers / Total_Passengers > (
    SELECT AVG(International_Passengers / Total_Passengers)
    FROM airport
);

SELECT Name 
FROM pilot 
WHERE Pilot_Id NOT IN (SELECT Winning_Pilot FROM match);

SELECT Airport_Name 
FROM airport 
WHERE Airport_ID NOT IN (
    SELECT Airport_ID 
    FROM airport_aircraft
);

SELECT 
    SUM(CASE WHEN fault_status = 'Fixed' THEN 1 ELSE 0 END) * 100.0 / COUNT(*) 
FROM Engineer_Visits;

SELECT * 
FROM Engineer_Visits 
WHERE contact_staff_id NOT IN (
    SELECT staff_id 
    FROM Staff
);
